class BackgroundAnimation{init(n,t,i,r,u){this.primaryColour=n||"red";this.secondaryColour=t||"blue";this.baseColour=i||"white";this.elementCount=r||130;this.linkDistance=u||140;this.elements=[];this.lines=[];this.initCanvas();this.addElements();this.draw(this)}initCanvas(){var n=this.canvas||document.createElement("canvas");document.body.prepend(n);n.style.position="absolute";n.style.top=0;n.style.left=0;n.style.zIndex=-1;n.width="100%";n.height="100%";n.style.pointerEvents="none";this.canvas=n}draw(n){var t=n.canvas.getContext("2d");t.fillStyle=n.baseColour;t.rect(0,0,n.canvas.width,n.canvas.height);t.fill();for(let i in n.elements)n.drawElement(t,n.elements[i]);n.elements.map(function(t){t.y<-10&&(t.y=n.canvas.height+t.r);t.x<-10&&(t.x=n.canvas.width+t.r);t.x>n.canvas.width+10&&(t.x=0-t.r);t.y>n.canvas.height+10&&(t.y=0-t.r)});window.requestAnimationFrame(()=>n.draw(n))}addElements(){for(var n=0;n<this.elementCount;n++)this.elements.push({i:n,x:Math.random()*(this.canvas.width+10)-10,y:Math.random()*(this.canvas.height+10)-10,r:Math.random()*2+.5,dir:{x:Math.random()*(Math.floor(Math.random()*2)==1?1:-1),y:Math.random()*(Math.floor(Math.random()*2)==1?1:-1)},col:Math.random()>.5?this.primaryColour:this.secondaryColour})}drawElement(n,t){var i=this,r;n.beginPath();n.arc(t.x,t.y,t.r,0,2*Math.PI);n.fillStyle=t.col;n.fill();r=i.elements.filter((n,r)=>i.getNearbyElements(i,t,n,r));i.lines=i.lines.concat(r.map(function(n){return{from:t.i,to:n.i}}));r.map(function(r){i.drawLine(n,t,r)});t.x+=t.dir.x*.2+.1;t.y+=t.dir.y*.2+.1}getNearbyElements(n,t,i){var r=Math.abs(i.x-t.x),u=Math.abs(i.y-t.y);return r+u<=n.linkDistance&&r+u!==0&&!n.lines.some(function(n){return n.from.i===t.i&&n.to.i===i.i})}drawLine(n,t,i){n.beginPath();n.moveTo(t.x,t.y);n.lineTo(i.x,i.y);var r=n.createLinearGradient(t.x,t.y,i.x,i.y);r.addColorStop(0,t.col);r.addColorStop(1,i.col);n.strokeStyle=r;n.lineWidth=.2;n.stroke()}}